type User struct {
	Name string
	Role string
}

var users = map[string]*User{}

func main() {
	http.HandleFunc("/connect", connectHandler)
	http.HandleFunc("/chat", chatHandler)
	http.ListenAndServe(":8080", nil)
}

func connectHandler(w http.ResponseWriter, r *http.Request) {
	name := r.Header.Get("Name")
	role := r.Header.Get("Role")
	if name == "" || role == "" {
		http.Error(w, "Missing user information", http.StatusBadRequest)
		return
	}
	users[name] = &User{Name: name, Role: role}
	fmt.Fprintf(w, "User %s connected with role %s", name, role)
}

func chatHandler(w http.ResponseWriter, r *http.Request) {
	name := r.Header.Get("Name")
	user, exists := users[name]
	if !exists {
		http.Error(w, "User not connected", http.StatusUnauthorized)
		return
	}

	message := r.FormValue("message")
	if strings.HasPrefix(message, "/") {
		handleCommand(user, message)
	} else {
		fmt.Fprintf(w, "Message from %s: %s", user.Name, message)
	}
}

func handleCommand(user *User, message string) {
	if user.Role != "admin" {
		fmt.Printf("User %s attempted to use admin command\n", user.Name)
		return
	}

	parts := strings.Fields(message)
	command := parts[0]
	switch command {
	case "/kick":
		if len(parts) < 2 {
			fmt.Println("Usage: /kick <username>")
			return
		}
		kickUser(parts[1])
	case "/ban":
		if len(parts) < 2 {
			fmt.Println("Usage: /ban <username>")
			return
		}
		banUser(parts[1])
	case "/giveitems":
		if len(parts) < 3 {
			fmt.Println("Usage: /giveitems <username> <item>")
			return
		}
		giveItems(parts[1], parts[2])
	default:
		fmt.Println("Unknown command")
	}
}

func kickUser(username string) {
	delete(users, username)
	fmt.Printf("User %s has been kicked\n", username)
}

